package com.example.auth

import android.content.Context
import android.content.SharedPreferences
import androidx.annotation.VisibleForTesting

class AuthenticationManager private constructor(
    private val prefs: SharedPreferences
) {

    companion object {
        @Volatile private var instance: AuthenticationManager? = null

        private const val PREFS_NAME = "auth_manager_prefs"
        private const val KEY_AUTH_TOKEN = "key_auth_token"
        private const val KEY_USER_ID = "key_user_id"

        fun getInstance(context: Context): AuthenticationManager {
            return instance ?: synchronized(this) {
                instance ?: AuthenticationManager(
                    context.applicationContext.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
                ).also { instance = it }
            }
        }

        @VisibleForTesting
        fun createForTesting(prefs: SharedPreferences): AuthenticationManager = AuthenticationManager(prefs)
    }

    data class AuthState(
        val userId: String,
        val authToken: String
    )

    fun isLoggedIn(): Boolean {
        val token = prefs.getString(KEY_AUTH_TOKEN, null)
        val userId = prefs.getString(KEY_USER_ID, null)
        return !token.isNullOrBlank() && !userId.isNullOrBlank()
    }

    fun getAuthState(): AuthState? {
        val token = prefs.getString(KEY_AUTH_TOKEN, null)?.trim()
        val userId = prefs.getString(KEY_USER_ID, null)?.trim()
        if (token.isNullOrEmpty() || userId.isNullOrEmpty()) return null
        return AuthState(userId = userId, authToken = token)
    }

    fun getAuthToken(): String? = prefs.getString(KEY_AUTH_TOKEN, null)?.trim()?.takeIf { it.isNotEmpty() }

    fun getUserId(): String? = prefs.getString(KEY_USER_ID, null)?.trim()?.takeIf { it.isNotEmpty() }

    fun onAuthenticationSuccess(userId: String, authToken: String) {
        val u = userId.trim()
        val t = authToken.trim()
        require(u.isNotEmpty()) { "userId must not be blank" }
        require(t.isNotEmpty()) { "authToken must not be blank" }

        prefs.edit()
            .putString(KEY_USER_ID, u)
            .putString(KEY_AUTH_TOKEN, t)
            .apply()
    }

    fun updateAuthToken(authToken: String) {
        val t = authToken.trim()
        require(t.isNotEmpty()) { "authToken must not be blank" }
        prefs.edit().putString(KEY_AUTH_TOKEN, t).apply()
    }

    fun clearSession() {
        prefs.edit()
            .remove(KEY_USER_ID)
            .remove(KEY_AUTH_TOKEN)
            .apply()
    }
}